const { createClient } = require('@supabase/supabase-js');
const sb = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
(async () => {
  async function walk(prefix, depth=0) {
    if (depth > 4) return 0;
    let count = 0;
    let offset = 0;
    while (true) {
      const { data, error } = await sb.storage.from('uploads').list(prefix, { limit: 1000, offset });
      if (error || !data || data.length === 0) break;
      for (const f of data) {
        if (f.id === null) { // folder
          count += await walk(prefix+'/'+f.name, depth+1);
        } else {
          count++;
        }
      }
      if (data.length < 1000) break;
      offset += 1000;
    }
    return count;
  }
  const trainTotal = await walk('training');
  console.log('training/ total files (recursive):', trainTotal);
  for (const u of ['cmmdqxc9m000013pm3xbsntl9','cmme0gvak0000sha2gv5f0jl0','cmmf7ypnk0000911kt5ojl4p2']) {
    const c = await walk(u);
    console.log(u, 'total files (recursive):', c);
  }
})().catch(e => console.error(e.message));
